UPDATE comments
SET contents = #{contents}
WHERE id = #{commentId}
  AND deleted_at IS NULL

mapper.select:
SELECT c.id AS comment_id, c.user_id AS author_id, u.nickname AS author_nickname, c.contents, (c.deleted_at IS NOT NULL) AS deleted, (c.modified_at IS NOT NULL AND c.deleted_at IS NULL) AS edited, c.parent_comment_id, c.created_at FROM comments c JOIN users u ON u.id = c.user_id
c.post_id = #{postId} AND c.parent_comment_id IS NULL AND ( c.deleted_at IS NULL OR EXISTS ( SELECT 1 FROM comments r WHERE r.parent_comment_id = c.id AND r.deleted_at IS NULL ) )
AND c.id < #{cursor}
ORDER BY c.id DESC LIMIT #{size}

SELECT c.id AS comment_id, c.user_id AS author_id, u.nickname AS author_nickname, c.contents, false AS deleted, (c.modified_at IS NOT NULL) AS edited, c.parent_comment_id, c.created_at FROM comments c JOIN users u ON u.id = c.user_id WHERE c.deleted_at IS NULL AND c.parent_comment_id IN
#{pid}
ORDER BY c.id ASC

